// Extrair vaga do body
const vaga = $input.body.vaga || '';

if (!vaga || vaga.trim().length === 0) {
  return {
    success: false,
    error: 'Campo "vaga" é obrigatório no body da requisição'
  };
}

return {
  success: true,
  vaga: vaga.trim()
};

// Parse dos arquivos JSON
const perfilBuffer = $input.item(0).binary.data;
const preferenciaBuffer = $input.item(1).binary.data;
const promptBuffer = $input.item(2).binary.data;
const vagaData = $input.item(3).json;

const perfil = JSON.parse(perfilBuffer.toString('utf8'));
const preferencias = JSON.parse(preferenciaBuffer.toString('utf8'));
const promptTemplate = promptBuffer.toString('utf8');

return {
  perfil,
  preferencias,
  promptTemplate,
  vaga: vagaData.vaga
};

const perfil = $input.json.perfil;
const preferencias = $input.json.preferencias;
const vaga = $input.json.vaga;
const promptTemplate = $input.json.promptTemplate;

// Formatar perfil
let perfilFormatado = 'PERFIL PROFISSIONAL:\n';
perfilFormatado += `Nome: ${perfil.informacoes_pessoais.nome}\n`;
perfilFormatado += `Objetivo: ${perfil.informacoes_pessoais.objetivo}\n\n`;

perfilFormatado += 'FORMAÇÃO:\n';
perfilFormatado += `Curso: ${perfil.formacao.curso}\n`;
perfilFormatado += `Instituição: ${perfil.formacao.instituicao}\n`;
perfilFormatado += `Período: ${perfil.formacao.periodo}\n\n`;

perfilFormatado += 'STACK TECNOLÓGICO:\n';
perfilFormatado += `Linguagens: ${perfil.stack_principal.linguagens.join(', ')}\n`;
perfilFormatado += `Frameworks Backend: ${perfil.stack_principal.frameworks_backend.join(', ')}\n`;
perfilFormatado += `Frameworks Frontend: ${perfil.stack_principal.frameworks_frontend.join(', ')}\n`;
perfilFormatado += `Bancos de Dados: ${perfil.stack_principal.bancos_dados.join(', ')}\n`;
perfilFormatado += `Cloud: ${perfil.stack_principal.cloud.join(', ')}\n`;
perfilFormatado += `DevOps: ${perfil.stack_principal.devops.join(', ')}\n\n`;

perfilFormatado += 'PROJETOS:\n';
for (const proj of perfil.projetos) {
  perfilFormatado += `- ${proj.nome}: ${proj.descricao}\n`;
  perfilFormatado += `  Stack: ${proj.stack.join(', ')}\n`;
}

perfilFormatado += '\nCERTIFICAÇÕES:\n';
for (const cert of perfil.certificacoes) {
  perfilFormatado += `- ${cert}\n`;
}

perfilFormatado += '\nFORÇAS:\n';
for (const forca of perfil.forcas) {
  perfilFormatado += `- ${forca}\n`;
}

// Formatar preferências
let preferenciaFormatada = 'PREFERÊNCIAS DO CANDIDATO:\n\n';

preferenciaFormatada += 'CARGOS DESEJADOS:\n';
for (const cargo of preferencias.cargo_desejado) {
  preferenciaFormatada += `- ${cargo}\n`;
}

preferenciaFormatada += '\nMODALIDADE DE TRABALHO:\n';
for (const mod of preferencias.modalidade) {
  preferenciaFormatada += `- ${mod}\n`;
}

preferenciaFormatada += '\nLOCALIZAÇÃO:\n';
for (const loc of preferencias.localizacao) {
  preferenciaFormatada += `- ${loc}\n`;
}

preferenciaFormatada += '\nTIPO DE CONTRATO:\n';
for (const tipo of preferencias.tipo_contrato) {
  preferenciaFormatada += `- ${tipo}\n`;
}

preferenciaFormatada += '\nPRIORIDADES:\n';
for (const prio of preferencias.prioridades) {
  preferenciaFormatada += `- ${prio}\n`;
}

preferenciaFormatada += '\nACEITÁVEL:\n';
for (const ace of preferencias.aceitavel) {
  preferenciaFormatada += `- ${ace}\n`;
}

preferenciaFormatada += '\nEVITAR:\n';
for (const eva of preferencias.evitar) {
  preferenciaFormatada += `- ${eva}\n`;
}

// Montar prompt final
let promtFinal = promptTemplate
  .replace('{{PERFIL}}', perfilFormatado)
  .replace('{{PREFERENCIAS}}', preferenciaFormatada)
  .replace('{{VAGA}}', vaga);

return {
  promptFinal,
  vaga
};

const resposta = $input.json.response || '';

// Extrair JSON da resposta
const inicio = resposta.indexOf('{');
const fim = resposta.lastIndexOf('}');

if (inicio === -1 || fim === -1 || inicio >= fim) {
  return {
    success: false,
    error: 'Não consegui extrair JSON válido da resposta do Ollama',
    resposta_bruta: resposta.substring(0, 200)
  };
}

const jsonStr = resposta.substring(inicio, fim + 1);

try {
  const analise = JSON.parse(jsonStr);
  return {
    success: true,
    analise
  };
} catch (e) {
  return {
    success: false,
    error: 'Erro ao fazer parse do JSON',
    erro_detalhes: e.message,
    json_tentado: jsonStr.substring(0, 200)
  };
}
